import { Search, Bell, User } from "lucide-react";

export default function Header() {
  return (
    <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 sticky top-0 z-10 w-full">
      {/* LEFT: Page Info & Tabs */}
      <div className="flex items-center gap-12">
        <h2 className="text-sm font-black text-slate-900 tracking-[0.15em] uppercase border-r border-slate-200 pr-8">
          Dashboard
        </h2>
        <nav className="flex gap-8">
          {["Monitoring", "Analytics", "Automation"].map((tab) => (
            <button
              key={tab}
              className={`text-xs font-bold uppercase tracking-wider pb-5 transition-all relative ${
                tab === "Monitoring" 
                  ? "text-cyan-600 after:content-[''] after:absolute after:bottom-[-20px] after:left-0 after:w-full after:h-[3px] after:bg-cyan-500" 
                  : "text-slate-400 hover:text-slate-600"
              }`}
            >
              {tab}
            </button>
          ))}
        </nav>
      </div>

      {/* RIGHT: Search, Notifications, Profile */}
      <div className="flex items-center gap-6">
        <div className="relative group">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-cyan-500 transition-colors" />
          <input
            type="text"
            placeholder="Search salinity nodes..."
            className="bg-slate-50 border-none rounded-xl pl-10 pr-4 py-2 text-xs w-64 focus:ring-1 focus:ring-cyan-200 focus:bg-white transition-all outline-none"
          />
        </div>

        <button className="relative p-2 text-slate-400 hover:bg-slate-50 rounded-full transition-colors">
          <Bell className="w-5 h-5" />
          <span className="absolute top-2 right-2.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
        </button>

        <div className="flex items-center gap-3 pl-6 border-l border-slate-200">
          <div className="text-right">
            <p className="text-[11px] font-black text-slate-900 uppercase leading-none mb-1">Tran Gia Hien</p>
            <p className="text-[9px] text-slate-500 font-bold uppercase tracking-wider">Chief Hydrologist</p>
          </div>
          <div className="w-10 h-10 rounded-full bg-slate-100 border border-slate-200 overflow-hidden flex items-center justify-center group cursor-pointer hover:border-cyan-300 transition-all">
             <User className="w-6 h-6 text-slate-400 group-hover:text-cyan-500" />
          </div>
        </div>
      </div>
    </header>
  );
}